	assert.True(t, m.appConfig.AutoAdvanceWaves)
	assert.Equal(t, 0, orch.FailedTaskCount())
}

// TestAutoAdvanceWaves_ShowsConfirmOnFailure verifies that even when AutoAdvanceWaves
