	instances := updated.nav.GetInstances()
	require.NotEmpty(t, instances, "solo stage must spawn an agent instance")
	soloInst := instances[len(instances)-1]
	assert.Contains(t, soloInst.QueuedPrompt, "kas task show "+planFile,
